import{_ as a,o as i,c as l,a2 as s}from"./chunks/framework.CHSDihme.js";const t="/claude-code-token-free/assets/dingding01.BOShwp3X.png",d="/claude-code-token-free/assets/dingding02.BNKQQaEy.png",g=JSON.parse('{"title":"钉钉接入","description":"","frontmatter":{},"headers":[],"relativePath":"im/dingtalk.md","filePath":"im/dingtalk.md","lastUpdated":1780324203000}'),o={name:"im/dingtalk.md"};function c(n,e,r,p,h,k){return i(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="钉钉接入" tabindex="-1">钉钉接入 <a class="header-anchor" href="#钉钉接入" aria-label="Permalink to &quot;钉钉接入&quot;">​</a></h1><blockquote><p>钉钉 Adapter 的接入教程。钉钉走 DingTalk Stream，不需要公网回调地址。</p></blockquote><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>钉钉方案适合通过钉钉单聊远程驱动本机 Claude Code。当前实现只处理单聊消息，不处理群聊。</p><p>当前实现支持文本聊天、图片附件、项目选择、状态查看、停止生成、AI Card 流式输出，以及文本或卡片形式的权限审批。</p><p>实现入口：<code>adapters/dingtalk/index.ts</code></p><h2 id="1-绑定钉钉机器人" tabindex="-1">1. 绑定钉钉机器人 <a class="header-anchor" href="#1-绑定钉钉机器人" aria-label="Permalink to &quot;1. 绑定钉钉机器人&quot;">​</a></h2><p>打开桌面端 <code>设置 -&gt; IM 接入 -&gt; 钉钉</code>。</p><p>推荐使用扫码绑定：</p><ol><li>点击「扫码绑定」。</li><li>使用钉钉手机 App 扫码。</li><li>在钉钉里确认创建并授权机器人。</li><li>等待桌面端显示「钉钉机器人已绑定」。</li><li>点击保存，或确认当前配置已经写入本地。</li></ol><p>授权成功后，桌面端会把 <code>clientId</code> 和 <code>clientSecret</code> 写入 <code>~/.claude/adapters.json</code> 的 <code>dingtalk</code> 配置。发布版桌面端会重启 adapter sidecar，让新凭据立即生效。</p><p><img src="'+t+'" alt="钉钉机器人绑定和手动凭据配置"></p><h2 id="2-手动填写凭据" tabindex="-1">2. 手动填写凭据 <a class="header-anchor" href="#2-手动填写凭据" aria-label="Permalink to &quot;2. 手动填写凭据&quot;">​</a></h2><p>如果扫码不可用，也可以手动填写：</p><ul><li><code>Client ID</code> — 钉钉应用的 <code>appKey</code></li><li><code>Client Secret</code> — 钉钉应用的 <code>appSecret</code></li><li><code>Stream Endpoint</code> — 可选，默认 <code>https://api.dingtalk.com</code></li><li><code>权限卡片模板 ID</code> — 可选，配置后权限请求优先使用钉钉互动卡片</li><li><code>Allowed Users</code> — 可选，直接放行指定钉钉用户 ID</li></ul><p>保存后 adapter 会用 DingTalk Stream 建立长连接。</p><h2 id="3-授权具体钉钉用户" tabindex="-1">3. 授权具体钉钉用户 <a class="header-anchor" href="#3-授权具体钉钉用户" aria-label="Permalink to &quot;3. 授权具体钉钉用户&quot;">​</a></h2><p>机器人绑定完成后，还需要让具体用户通过配对码授权：</p><ol><li>在 <code>设置 -&gt; IM 接入</code> 顶部的「配对管理」里点击「生成配对码」。</li><li>在钉钉机器人单聊里发送这枚 6 位配对码。</li><li>看到配对成功提示后，就可以开始聊天。</li></ol><p><img src="'+d+`" alt="钉钉里发送配对码并开始对话"></p><p>配对码有效期 60 分钟，一次性使用。配对用户会出现在「已配对用户」列表里，可以随时解绑。解绑后该用户需要重新发送新的配对码才能使用。</p><h2 id="4-选择项目并开始对话" tabindex="-1">4. 选择项目并开始对话 <a class="header-anchor" href="#4-选择项目并开始对话" aria-label="Permalink to &quot;4. 选择项目并开始对话&quot;">​</a></h2><p>如果已经配置默认项目，发送任意消息会直接在该目录下创建或复用 Claude Code session。</p><p>如果没有配置默认项目，adapter 会返回最近项目列表。回复编号、项目名或绝对路径后，会新建会话并绑定到当前钉钉 chat。</p><p>后续消息会复用 <code>~/.claude/adapter-sessions.json</code> 里的 chat 到 session 映射。发送 <code>/new</code> 可以重新选择项目并开启新会话。</p><h2 id="支持的命令" tabindex="-1">支持的命令 <a class="header-anchor" href="#支持的命令" aria-label="Permalink to &quot;支持的命令&quot;">​</a></h2><p>钉钉这里没有像飞书那样的机器人菜单配置流程；当前命令入口就是单聊输入框。配对成功后，bot 会提示发送 <code>/help</code>；用户也可以随时发送 <code>/help</code> 或 <code>帮助</code> 查看完整命令列表。</p><ul><li><code>/help</code> 或 <code>帮助</code> — 显示可用命令</li><li><code>/status</code> 或 <code>状态</code> — 查看当前会话的项目、分支、模型、运行状态和任务摘要</li><li><code>/projects</code> 或 <code>项目列表</code> — 重新显示最近项目列表</li><li><code>/new</code> 或 <code>新会话</code> — 清空当前 chat 绑定的 session，并重新选择项目</li><li><code>/new &lt;编号、项目名或绝对路径&gt;</code> — 直接在指定项目下新建会话</li><li><code>/clear</code> 或 <code>清空</code> — 清空当前会话上下文，保留项目绑定</li><li><code>/stop</code> 或 <code>停止</code> — 向当前 session 发送 <code>stop_generation</code></li></ul><h2 id="权限审批" tabindex="-1">权限审批 <a class="header-anchor" href="#权限审批" aria-label="Permalink to &quot;权限审批&quot;">​</a></h2><p>默认情况下，钉钉 adapter 会发送文本审批消息。回复：</p><ul><li><code>/allow &lt;requestId&gt;</code> — 允许一次权限请求</li><li><code>/always &lt;requestId&gt;</code> — 永久允许同类权限请求</li><li><code>/deny &lt;requestId&gt;</code> — 拒绝一次权限请求</li></ul><p>如果配置了已发布的钉钉互动卡片模板 ID，adapter 会优先发送权限卡片，并通过 DingTalk Stream 的 <code>/v1.0/card/instances/callback</code> 接收按钮回调。卡片发送失败或不可见时，仍可使用文本命令审批。</p><h2 id="返回消息的表现" tabindex="-1">返回消息的表现 <a class="header-anchor" href="#返回消息的表现" aria-label="Permalink to &quot;返回消息的表现&quot;">​</a></h2><ul><li>使用 <code>dingtalk-stream</code> 接收机器人单聊消息。</li><li>使用消息里的 <code>sessionWebhook</code> 回复 Markdown 文本。</li><li>普通回复优先使用 AI Card 做流式输出。</li><li>权限审批可以使用互动卡片；没有模板时自动回退文本命令。</li><li>图片附件会下载后以内联图片形式进入模型输入。</li><li>附件会走公共大小限制检查，超限时 adapter 会在钉钉里返回提示。</li></ul><h2 id="解绑" tabindex="-1">解绑 <a class="header-anchor" href="#解绑" aria-label="Permalink to &quot;解绑&quot;">​</a></h2><p>有两种解绑：</p><ul><li>解绑钉钉机器人账号：在钉钉标签页点击「解绑机器人账号」，会清空 <code>dingtalk.clientId</code>、<code>dingtalk.clientSecret</code>、<code>allowedUsers</code>、<code>pairedUsers</code> 和权限卡片模板 ID。</li><li>解绑某个用户：在「已配对用户」列表里点击对应钉钉用户右侧的「解绑」，只移除该用户的 <code>pairedUsers</code> 记录。</li></ul><p>解绑机器人账号后需要重新扫码或手动填写凭据。解绑用户后，该用户需要重新发送新的配对码才能继续使用。</p><h2 id="本地开发启动" tabindex="-1">本地开发启动 <a class="header-anchor" href="#本地开发启动" aria-label="Permalink to &quot;本地开发启动&quot;">​</a></h2><p>发布版桌面端会自动启动 adapter sidecar。只有本地开发或单独调试时才需要手动运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> adapters</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dingtalk</span></span></code></pre></div><p>可选环境变量：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DINGTALK_CLIENT_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DINGTALK_CLIENT_SECRET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DINGTALK_STREAM_ENDPOINT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.dingtalk.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DINGTALK_PERMISSION_CARD_TEMPLATE_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADAPTER_SERVER_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ws://127.0.0.1:3456&quot;</span></span></code></pre></div><p>正常桌面端使用不需要手动设置这些环境变量，扫码绑定或手动填写会写入本地配置。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="扫码成功后发消息仍提示未授权" tabindex="-1">扫码成功后发消息仍提示未授权 <a class="header-anchor" href="#扫码成功后发消息仍提示未授权" aria-label="Permalink to &quot;扫码成功后发消息仍提示未授权&quot;">​</a></h3><p>这是正常授权流程的一部分。扫码绑定只写入机器人凭据；具体钉钉用户还需要发送配对码，或被加入 <code>Allowed Users</code>。</p><h3 id="扫码失败或一直等待确认" tabindex="-1">扫码失败或一直等待确认 <a class="header-anchor" href="#扫码失败或一直等待确认" aria-label="Permalink to &quot;扫码失败或一直等待确认&quot;">​</a></h3><p>重新点击「扫码绑定」生成新二维码。如果仍失败，可以手动填写 <code>Client ID</code> 和 <code>Client Secret</code>。</p><h3 id="adapter-启动时报缺少-clientid--clientsecret" tabindex="-1">adapter 启动时报缺少 clientId / clientSecret <a class="header-anchor" href="#adapter-启动时报缺少-clientid--clientsecret" aria-label="Permalink to &quot;adapter 启动时报缺少 clientId / clientSecret&quot;">​</a></h3><p>说明 <code>DINGTALK_CLIENT_ID / DINGTALK_CLIENT_SECRET</code> 和 <code>~/.claude/adapters.json</code> 里的 <code>dingtalk.clientId / dingtalk.clientSecret</code> 都没有生效。先在桌面端钉钉标签页完成扫码绑定或手动填写凭据。</p><h3 id="权限卡片没有出现" tabindex="-1">权限卡片没有出现 <a class="header-anchor" href="#权限卡片没有出现" aria-label="Permalink to &quot;权限卡片没有出现&quot;">​</a></h3><p>优先检查：</p><ul><li>是否已经配置发布后的权限卡片模板 ID。</li><li>模板是否支持 adapter 使用的回调路由。</li><li>当前机器人是否已经发布新版本。</li></ul><p>即使卡片不可见，也可以用 <code>/allow &lt;requestId&gt;</code>、<code>/always &lt;requestId&gt;</code>、<code>/deny &lt;requestId&gt;</code> 完成审批。</p><h3 id="收不到回复" tabindex="-1">收不到回复 <a class="header-anchor" href="#收不到回复" aria-label="Permalink to &quot;收不到回复&quot;">​</a></h3><p>优先检查：</p><ul><li>桌面端是否正在运行。</li><li>钉钉标签页是否显示已绑定。</li><li>当前用户是否已经配对或在 <code>Allowed Users</code> 中。</li><li><code>~/.claude/adapters.json</code> 是否能正常写入。</li><li>本地开发时 <code>ADAPTER_SERVER_URL</code> 是否指向正在运行的 Desktop server WebSocket 地址。</li></ul><h3 id="会话没恢复" tabindex="-1">会话没恢复 <a class="header-anchor" href="#会话没恢复" aria-label="Permalink to &quot;会话没恢复&quot;">​</a></h3><p>检查 <code>~/.claude/adapter-sessions.json</code> 是否能正常写入，以及 Desktop server 里的 session 是否仍存在。</p><h2 id="源码入口" tabindex="-1">源码入口 <a class="header-anchor" href="#源码入口" aria-label="Permalink to &quot;源码入口&quot;">​</a></h2><ul><li><code>adapters/dingtalk/index.ts</code></li><li><code>adapters/dingtalk/helpers.ts</code></li><li><code>adapters/dingtalk/ai-card.ts</code></li><li><code>adapters/dingtalk/permission-card.ts</code></li><li><code>adapters/dingtalk/media.ts</code></li><li><code>adapters/common/pairing.ts</code></li><li><code>adapters/common/session-store.ts</code></li><li><code>adapters/common/ws-bridge.ts</code></li><li><code>adapters/common/http-client.ts</code></li></ul>`,62)])])}const b=a(o,[["render",c]]);export{g as __pageData,b as default};
